import json
from typing import List, Tuple

def validate_jsonl(filepath: str) -> Tuple[bool, List[str]]:
    """Validate JSONL training file format."""

    errors = []

    with open(filepath, 'r') as f:
        for i, line in enumerate(f, 1):
            try:
                data = json.loads(line)
            except json.JSONDecodeError as e:
                errors.append(f"Line {i}: Invalid JSON - {e}")
                continue

            # Check for messages key
            if "messages" not in data:
                errors.append(f"Line {i}: Missing 'messages' key")
                continue

            messages = data["messages"]

            # Check messages is a list
            if not isinstance(messages, list):
                errors.append(f"Line {i}: 'messages' must be a list")
                continue

            # Check each message
            roles_seen = []
            for j, msg in enumerate(messages):
                if "role" not in msg:
                    errors.append(f"Line {i}, msg {j}: Missing 'role'")
                if "content" not in msg:
                    errors.append(f"Line {i}, msg {j}: Missing 'content'")

                if "role" in msg:
                    roles_seen.append(msg["role"])

            # Check for required roles
            if "assistant" not in roles_seen:
                errors.append(f"Line {i}: No assistant message")

            if "user" not in roles_seen:
                errors.append(f"Line {i}: No user message")

    return len(errors) == 0, errors

# Usage
valid, errors = validate_jsonl("training.jsonl")
if not valid:
    for error in errors:
        print(error)

import json
from typing import List
from dataclasses import dataclass

@dataclass
class ValidationResult:
    valid: bool
    errors: List[str]
    warnings: List[str]
    stats: dict

class TrainingDataValidator:
    """Validate training data format and quality."""

    def __init__(
        self,
        min_examples: int = 10,
        max_tokens_per_example: int = 4096
    ):
        self.min_examples = min_examples
        self.max_tokens = max_tokens_per_example

    def validate_file(self, filepath: str) -> ValidationResult:
        """Validate JSONL file."""
        errors = []
        warnings = []

        examples = []
        with open(filepath, 'r') as f:
            for i, line in enumerate(f, 1):
                try:
                    data = json.loads(line)
                    examples.append(data)
                except json.JSONDecodeError as e:
                    errors.append(f"Line {i}: Invalid JSON - {e}")

        # Check minimum examples
        if len(examples) < self.min_examples:
            errors.append(
                f"Insufficient examples: {len(examples)} < {self.min_examples}"
            )

        # Validate each example
        for i, example in enumerate(examples, 1):
            example_errors = self._validate_example(example, i)
            errors.extend(example_errors)

        # Quality warnings
        quality_warnings = self._check_quality(examples)
        warnings.extend(quality_warnings)

        # Stats
        stats = self._calculate_stats(examples)

        return ValidationResult(
            valid=len(errors) == 0,
            errors=errors,
            warnings=warnings,
            stats=stats
        )

    def _validate_example(self, example: dict, index: int) -> List[str]:
        errors = []

        # SFT format
        if "messages" in example:
            messages = example["messages"]

            if not isinstance(messages, list):
                errors.append(f"Example {index}: 'messages' must be list")
                return errors

            roles = [m.get("role") for m in messages]

            if "assistant" not in roles:
                errors.append(f"Example {index}: No assistant message")
            if "user" not in roles:
                errors.append(f"Example {index}: No user message")

        # DPO format
        elif "input" in example:
            required = ["input", "preferred_output", "non_preferred_output"]
            for key in required:
                if key not in example:
                    errors.append(f"Example {index}: Missing '{key}'")

        else:
            errors.append(f"Example {index}: Unknown format")

        return errors

    def _check_quality(self, examples: List[dict]) -> List[str]:
        warnings = []

        # Check for duplicates
        seen = set()
        for i, ex in enumerate(examples):
            key = json.dumps(ex, sort_keys=True)
            if key in seen:
                warnings.append(f"Duplicate example at index {i}")
            seen.add(key)

        return warnings

    def _calculate_stats(self, examples: List[dict]) -> dict:
        return {
            "total_examples": len(examples),
            "format": "sft" if examples and "messages" in examples[0] else "dpo"
        }

